# Exercício 6 - Monitor de Desempenho da CPU\n\n# importo as bibliotecas\nimport psutil\nimport time\nimport os\n\n# limpo a tela\nos.system(\"cls\")\n\nprint(\"=\"*70)\nprint(\"       MONITOR DE DESEMPENHO DA CPU\")\nprint(\"=\"*70)\nprint(\"Monitorando... Pressione Ctrl+C para interromper\\n\")\n\ntry:\n    while True:\n        # psutil.cpu_percent(interval=1, percpu=True) calcula o uso de CPU\n        # interval=1: aguarda 1 segundo entre medições para cálculo preciso\n        # percpu=True: retorna o uso de CADA núcleo separadamente\n        # percpu=False: retorna apenas o uso total\n        uso_por_nucleo = psutil.cpu_percent(interval=1, percpu=True)\n\n        # calculo o uso total da CPU (média de todos os núcleos)\n        # sum() soma todos os valores\n        # len() conta quantos elementos há\n        # então divisão dá a média\n        uso_total = sum(uso_por_nucleo) / len(uso_por_nucleo)\n\n        # limpo a tela\n        os.system(\"cls\")\n\n        # exibo as informações\n        print(\"\\n\" + \"=\"*70)\n        print(\"       MONITOR DE DESEMPENHO DA CPU\")\n        print(\"=\"*70)\n        print(f\"\\nCPU Total: {uso_total:.1f}%\\n\")\n\n        # exibo o uso de cada núcleo\n        print(\"Uso por Núcleo:\")\n        print(\"-\" * 70)\n\n        # loop para cada núcleo\n        for numero_nucleo, percentual in enumerate(uso_por_nucleo):\n            # crio uma barra visual simples\n            # cada # representa ~5% de uso\n            barra = \"#\" * int(percentual / 5)\n            print(f\"Núcleo {numero_nucleo}: {percentual:>6.1f}% {barra}\")\n\n        print(\"=\"*70)\n        print(f\"Número de núcleos (lógicos): {len(uso_por_nucleo)}\")\n        print(\"=\"*70)\n        print(\"Pressione Ctrl+C para interromper\")\n\nexcept KeyboardInterrupt:\n    # se pressionar Ctrl+C, encerro\n    print(\"\\n\\nPrograma interrompido pelo usuário.\")\n\n# Anotações:\n# - psutil.cpu_percent(interval, percpu):\n#   * interval: tempo em segundos para medir (quanto maior, mais preciso)\n#   * percpu: se True retorna lista com cada núcleo; se False retorna total\n# - uso_por_nucleo é uma LISTA com o percentual de cada núcleo\n#   * exemplo: [10.5, 15.3, 8.2, 12.1] para 4 núcleos\n# - sum(lista) soma todos os elementos de uma lista\n# - len(lista) retorna o tamanho (quantidade de elementos)\n# - média = sum() / len() é a fórmula básica\n# - enumerate(lista) retorna ÍNDICE e VALOR simultaneamente\n#   * exemplo: for numero, valor in enumerate([10, 20, 30])\n#   * primeira iteração: numero=0, valor=10\n#   * segunda iteração: numero=1, valor=20\n# - barra visual: \"#\" * int(percentual / 5) cria uma barra com caracteres\n#   * 100% / 5 = 20 hashes\n#   * 50% / 5 = 10 hashes\n#   * e assim por diante\n